#include <bits/stdc++.h>
using namespace std;
struct serve{
	string s;
	int id;
}p[1003];
int n,sum=0;
bool check(string t){
	int j=0,cnt1=0,cnt2=0;
	for(int i=0;i<t.size();i++){
	    if(t[i]=='.'){
	        cnt1++;
	        if(cnt2 || i==0 || i==t.size()-1 || t[i+1]=='.' || t[i-1]=='.' || t[i+1]==':' || t[i-1]==':')return false;
	    }else if(t[i]==':'){
	        cnt2++;
	        if(cnt1!=3 || i==0 || i==t.size()-1 || t[i+1]=='.' || t[i-1]=='.' || t[i+1]==':' || t[i-1]==':')return false;
	    }
	}
	if(cnt1!=3 || cnt2!=1)return false;
	for(int i=1;i<=5;i++){
		if(t[j]=='0' && '0'<=t[j+1] && t[j+1]<='9')return false;
		long long num=0;
		while(j<t.size() && '0'<=t[j] && t[j]<='9'){
			num=num*10+t[j++]-'0';
			if(i<=4 && num>255 || num>65535)return false;
		}
		if(i<=4 && num>255 || num>65535)return false;
		j++;
		//if(j=='.' || j==':')return false;
	}
	return true;
}
int Find(string t){
	for(int i=1;i<=sum;i++)if(p[i].s==t)return p[i].id;
	return -1;
}
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		string op,ad;
		cin>>op>>ad;
		if(!check(ad))cout<<"ERR\n";
		else if(op=="Server"){
			if(Find(ad)!=-1)cout<<"FAIL\n";
			else{
				cout<<"OK\n";
				p[++sum]={ad,i};
			}
		}else{
			int f=Find(ad);
			if(f==-1)cout<<"FAIL\n";
			else cout<<f<<endl;
		}
	}
	return 0;
}
